/**
 * Demand Map Page — Shows confirmed demand insights.
 *
 * Displays demand cards in a grid with:
 * - Demand category, description, frequency, trend arrow, suggested action
 * - Only shows type === 'demand' and reviewStatus === 'confirmed'
 */

import React, { useEffect, useMemo } from 'react';
import {
  Box,
  Typography,
  Card,
  CardContent,
  Chip,
  Grid,
} from '@mui/material';
import MapIcon from '@mui/icons-material/Map';
import TrendingUpIcon from '@mui/icons-material/TrendingUp';
import TrendingDownIcon from '@mui/icons-material/TrendingDown';
import TrendingFlatIcon from '@mui/icons-material/TrendingFlat';
import { useBrandStore } from '@/shared/stores/brandStore';
import { useInsightStore } from '@/shared/stores/insightStore';
import type { Demand } from '@/shared/types/insight';

/** Category color map */
const CATEGORY_COLORS: Record<string, 'primary' | 'success' | 'warning' | 'info' | 'error'> = {
  '人群适配': 'primary',
  '场景需求': 'info',
  '效果验证': 'success',
  '使用教育': 'warning',
  '竞品替代': 'error',
  '成分安全': 'success',
  '价格替代': 'warning',
};

function getCategoryColor(category: string): 'primary' | 'success' | 'warning' | 'info' | 'error' {
  return CATEGORY_COLORS[category] ?? 'primary';
}

function TrendIcon({ trend }: { trend: Demand['trend'] }) {
  if (trend === 'rising') return <TrendingUpIcon fontSize="small" color="success" />;
  if (trend === 'declining') return <TrendingDownIcon fontSize="small" color="error" />;
  return <TrendingFlatIcon fontSize="small" color="disabled" />;
}

function trendLabel(trend: Demand['trend']): string {
  if (trend === 'rising') return '上升';
  if (trend === 'declining') return '下降';
  return '稳定';
}

const DemandMapPage: React.FC = () => {
  const currentBrandId = useBrandStore((s) => s.currentBrandId);
  const brand = useBrandStore((s) => s.getCurrentBrand());
  const insights = useInsightStore((s) => s.insights);
  const loadInsights = useInsightStore((s) => s.loadInsights);

  const brandId = currentBrandId ?? '';

  useEffect(() => {
    if (brandId) loadInsights(brandId);
  }, [brandId, loadInsights]);

  // Filter: only confirmed demands
  const demands = useMemo(
    () =>
      insights.filter(
        (i) => i.type === 'demand' && i.reviewStatus === 'confirmed',
      ) as Demand[],
    [insights],
  );

  // Sort by frequency descending
  const sorted = useMemo(
    () => [...demands].sort((a, b) => b.frequency - a.frequency),
    [demands],
  );

  return (
    <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      {/* Header */}
      <Box
        sx={{
          p: 2,
          borderBottom: '1px solid',
          borderColor: 'divider',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
        }}
      >
        <Box>
          <Typography variant="h6" fontWeight={700}>
            🗺️ 需求地图
          </Typography>
          <Typography variant="body2" color="text.secondary">
            {brand?.name ?? ''} · 已确认需求 {sorted.length} 条
          </Typography>
        </Box>
      </Box>

      {/* Content */}
      <Box sx={{ flex: 1, overflow: 'auto', p: 2 }}>
        {sorted.length === 0 ? (
          <Box
            sx={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              height: '100%',
              gap: 2,
            }}
          >
            <MapIcon sx={{ fontSize: 48, color: 'text.disabled' }} />
            <Typography variant="body1" color="text.secondary">
              暂无已确认的需求洞察
            </Typography>
            <Typography variant="caption" color="text.disabled">
              请先在 AI 工作台运行分析，然后在审核工作台确认洞察
            </Typography>
          </Box>
        ) : (
          <Grid container spacing={2}>
            {sorted.map((demand) => (
              <Grid item xs={12} sm={6} md={4} key={demand.id}>
                <Card
                  sx={{
                    height: '100%',
                    display: 'flex',
                    flexDirection: 'column',
                    transition: 'box-shadow 0.2s',
                    '&:hover': { boxShadow: 4 },
                  }}
                >
                  <CardContent sx={{ flex: 1 }}>
                    {/* Category + Frequency */}
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 1 }}>
                      <Chip
                        label={demand.category}
                        size="small"
                        color={getCategoryColor(demand.category)}
                        sx={{ fontWeight: 600, fontSize: 11 }}
                      />
                      <Chip
                        label={`频次 ${demand.frequency}`}
                        size="small"
                        variant="outlined"
                        sx={{ fontSize: 11 }}
                      />
                    </Box>

                    {/* Title / Description */}
                    <Typography variant="subtitle2" fontWeight={600} gutterBottom>
                      {demand.title}
                    </Typography>
                    <Typography
                      variant="body2"
                      color="text.secondary"
                      sx={{
                        mb: 1.5,
                        display: '-webkit-box',
                        WebkitLineClamp: 3,
                        WebkitBoxOrient: 'vertical',
                        overflow: 'hidden',
                      }}
                    >
                      {demand.content}
                    </Typography>

                    {/* Trend + Action */}
                    <Box
                      sx={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: 0.5,
                        mb: 1,
                      }}
                    >
                      <TrendIcon trend={demand.trend} />
                      <Typography variant="caption" color="text.secondary">
                        趋势: {trendLabel(demand.trend)}
                      </Typography>
                    </Box>

                    {demand.suggestedAction && (
                      <Box
                        sx={{
                          mt: 1,
                          p: 1,
                          borderRadius: 1,
                          bgcolor: 'primary.50',
                          border: '1px solid',
                          borderColor: 'primary.100',
                        }}
                      >
                        <Typography variant="caption" fontWeight={600} color="primary.main">
                          💡 建议动作
                        </Typography>
                        <Typography variant="caption" color="text.secondary" sx={{ display: 'block', mt: 0.25 }}>
                          {demand.suggestedAction}
                        </Typography>
                      </Box>
                    )}
                  </CardContent>
                </Card>
              </Grid>
            ))}
          </Grid>
        )}
      </Box>
    </Box>
  );
};

export default DemandMapPage;
